#include <bits/stdc++.h>
using namespace std;

const int N=15;

int n;
double a[N][N],s[N][N],sum[N];

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n+1;i++)
        for(int j=1;j<=n;j++)
            scanf("%lf",&a[i][j]);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=n;j++){
            s[i][j]=2.0*(a[i][j]-a[i+1][j]);
            sum[i]+=a[i][j]*a[i][j];
        }
    for(int i=1;i<=n;i++)
        sum[n+1]+=a[n+1][i]*a[n+1][i];
    for(int i=1;i<=n;i++)
        s[i][n+1]=sum[i]-sum[i+1];
    for(int i=1;i<=n;i++){
        int r=i;
        for(int j=i+1;j<=n;j++)
            if(fabs(s[j][i])>fabs(s[r][i]))
                r=j;
        for(int j=i;j<=n+1;j++)
            swap(s[i][j],s[r][j]);
        double num=s[i][i];
        for(int j=i;j<=n+1;j++)
            s[i][j]/=num;
        for(int j=i+1;j<=n;j++){
            num=s[j][i];
            for(int k=i;k<=n+1;k++)
                s[j][k]-=num*s[i][k];
        }
    }
    for(int i=n;i;i--)
        for(int j=i-1;j;j--)
            s[j][n+1]-=s[j][i]*s[i][n+1],s[j][i]=0;
    for(int i=1;i<=n;i++)
        printf("%.3lf ",(s[i][n+1]?s[i][n+1]:0));
    return 0;
}
